704: // Process takes a raft message and applies it to the server's raft state
705: // machine, respecting any timeout of the given context.
706: func (s *EtcdServer) Process(ctx context.Context, m raftpb.Message) error {
707: 	lg := s.Logger()
708: 	if s.cluster.IsIDRemoved(types.ID(m.From)) {
709: 		lg.Warn(
710: 			"rejected Raft message from removed member",
711: 			zap.String("local-member-id", s.MemberID().String()),
712: 			zap.String("removed-member-id", types.ID(m.From).String()),
713: 		)
714: 		return httptypes.NewHTTPError(http.StatusForbidden, "cannot process message from removed member")
715: 	}
716: 	if s.MemberID() != types.ID(m.To) {
717: 		lg.Warn(
718: 			"rejected Raft message to mismatch member",
719: 			zap.String("local-member-id", s.MemberID().String()),
720: 			zap.String("mismatch-member-id", types.ID(m.To).String()),
721: 		)
722: 		return httptypes.NewHTTPError(http.StatusForbidden, "cannot process message to mismatch member")
723: 	}
724: 	if m.Type == raftpb.MsgApp {
725: 		s.stats.RecvAppendReq(types.ID(m.From).String(), m.Size())
726: 	}
727: 	return s.r.Step(ctx, m)
728: }
